"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[47302],{83488:e=>{e.exports=JSON.parse('{"tag":{"label":"diabetes","permalink":"/docs/tags/diabetes","allTagsPath":"/docs/tags","count":14,"items":[{"id":"Degus/illnesses-and-conditions/common-health-issues","title":"Common Health Issues in Degus","description":"An overview of the most common health issues affecting pet degus, including their genetic predisposition to diabetes, dental disease, tail slip, and bumblefoot.","permalink":"/docs/Degus/illnesses-and-conditions/common-health-issues"},{"id":"Degus/care-and-husbandry/dangerous-treats-and-toys","title":"Dangerous Treats and Toys for Degus","description":"A critical guide to dangerous treats and toys for degus, emphasizing the absolute prohibition of sugar to prevent diabetes, and outlining the dangers of plastic and unsafe woods.","permalink":"/docs/Degus/care-and-husbandry/dangerous-treats-and-toys"},{"id":"Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas","title":"Diabetes in Chinchillas","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in chinchillas, including diet and lifestyle changes.","permalink":"/docs/Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas"},{"id":"Degus/illnesses-and-conditions/diabetes-in-degus","title":"Diabetes in Degus","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in degus \u2014 one of the most diabetes-prone small mammals kept as pets.","permalink":"/docs/Degus/illnesses-and-conditions/diabetes-in-degus"},{"id":"Gerbils/illnesses-and-conditions/diabetes","title":"Diabetes in Gerbils","description":"A guide to diabetes in gerbils, a common condition often linked to diet, covering the signs, causes, and the importance of dietary management for prevention and care.","permalink":"/docs/Gerbils/illnesses-and-conditions/diabetes"},{"id":"guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs","title":"Diabetes in Guinea Pigs","description":"Learn about diabetes mellitus in guinea pigs \u2014 causes, symptoms, diagnosis, management, and how diet and lifestyle changes can help your guinea pig live well.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs"},{"id":"Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs","title":"Diabetes in Hedgehogs","description":"A comprehensive guide to diabetes in hedgehogs \u2014 causes, signs, diagnosis, and management strategies for this common metabolic condition.","permalink":"/docs/Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs"},{"id":"Hamsters/illnesses-and-conditions/diabetes-in-hamsters","title":"Diabetes in Pet Hamsters","description":"A comprehensive guide to diabetes in hamsters \u2014 which breeds are most at risk, signs and symptoms, diagnosis, and management strategies.","permalink":"/docs/Hamsters/illnesses-and-conditions/diabetes-in-hamsters"},{"id":"Mice/illnesses-and-conditions/diabetes-in-mice","title":"Diabetes in Pet Mice","description":"A guide to diabetes in pet mice \u2014 causes, symptoms, diagnosis, and management strategies for this metabolic condition.","permalink":"/docs/Mice/illnesses-and-conditions/diabetes-in-mice"},{"id":"Rabbits/illnesses-and-conditions/diabetes-in-rabbits","title":"Diabetes in Pet Rabbits","description":"A comprehensive guide to diabetes in rabbits \u2014 causes, symptoms, diagnosis, and management of this rare but serious metabolic condition.","permalink":"/docs/Rabbits/illnesses-and-conditions/diabetes-in-rabbits"},{"id":"Rats/illnesses-and-conditions/diabetes-in-rats","title":"Diabetes in Rats","description":"Diabetes Mellitus is a condition in which the body either fails to produce enough insulin or cannot use it effectively, resulting in persistently high blood sugar (hyperglycemia). While not common in pet rats, it does occur \u2014 particularly in older or overweight individuals \u2014 and requires prompt veterinary attention and a committed management plan. Understanding the signs, how diagnosis works, and what treatment looks like can make a significant difference for an affected rat 1.","permalink":"/docs/Rats/illnesses-and-conditions/diabetes-in-rats"},{"id":"Degus/health-and-wellness/eye-and-vision-issues","title":"Eye & Vision Issues in Degus","description":"A guide to common eye and vision issues in degus, with a focus on the strong link between cataracts and diabetes, as well as other problems like eye injuries and weeping eyes from dental disease.","permalink":"/docs/Degus/health-and-wellness/eye-and-vision-issues"},{"id":"Degus/health-and-wellness/gi-health","title":"Gastrointestinal (GI) Health in Degus","description":"An essential guide to gastrointestinal (GI) health in degus, covering their sensitive digestive system, the risks of bloat and stasis, and the connection between diet, GI health, and diabetes.","permalink":"/docs/Degus/health-and-wellness/gi-health"},{"id":"Ferrets/illnesses-and-conditions/diabetes-in-ferrets","title":"Understanding Diabetes in Ferrets","description":"When discussing pancreatic diseases in ferrets, it is crucial to distinguish between two very different conditions: Insulinoma and Diabetes Mellitus.","permalink":"/docs/Ferrets/illnesses-and-conditions/diabetes-in-ferrets"}],"unlisted":false}}')}}]);